-- Hira Industries catalogue product import
-- Source: Hira_Industries_catalogue(1).pdf
-- Extracted product rows: 172
-- Safe behavior:
--   - Upserts by product_code when product already exists.
--   - Inserts missing rows with image_url/gallery_images left null.
--   - Preserves existing product image_url and gallery_images.
--   - Uses active main categories under product_categories.
--   - Uses subcategory_id only when the active subcategory exists; otherwise leaves it null.

begin;

create temporary table tmp_hira_catalogue_products (
  product_name text not null,
  product_code text not null,
  slug text not null,
  main_category_slug text not null,
  subcategory_slug text null,
  short_description text not null,
  description text not null,
  material text null,
  available_colors text[] not null default '{}'::text[],
  features text[] not null default '{}'::text[],
  tags text[] not null default '{}'::text[],
  sort_order integer not null default 0,
  is_featured boolean not null default false,
  catalogue_page integer null
) on commit drop;

insert into tmp_hira_catalogue_products (
  product_name,
  product_code,
  slug,
  main_category_slug,
  subcategory_slug,
  short_description,
  description,
  material,
  available_colors,
  features,
  tags,
  sort_order,
  is_featured,
  catalogue_page
)
