-- Hard stop if any approved main category is missing/inactive.
do $$
begin
  if exists (
    select 1
    from tmp_hira_catalogue_products import
    left join public.product_categories category
      on category.slug = import.main_category_slug
      and category.is_active = true
    where category.id is null
  ) then
    raise exception 'Cannot import products: one or more active main categories are missing in public.product_categories.';
  end if;
end $$;

with resolved as (
  select
    import.*,
    category.id as category_id,
    subcategory.id as subcategory_id
  from tmp_hira_catalogue_products import
  join public.product_categories category
    on category.slug = import.main_category_slug
    and category.is_active = true
  left join public.product_categories subcategory
    on subcategory.slug = import.subcategory_slug
    and subcategory.parent_id = category.id
    and subcategory.is_active = true
)
update public.products product
set
  name = resolved.product_name,
  slug = resolved.slug,
  category_id = resolved.category_id,
  subcategory_id = resolved.subcategory_id,
  short_description = resolved.short_description,
  description = resolved.description,
  product_code = resolved.product_code,
  material = resolved.material,
  set_contents = null,
  pieces = null,
  available_colors = resolved.available_colors,
  features = resolved.features,
  tags = resolved.tags,
  is_featured = resolved.is_featured,
  is_active = true,
  sort_order = resolved.sort_order,
  updated_at = now()
from resolved
where product.product_code = resolved.product_code;

with resolved as (
  select
    import.*,
    category.id as category_id,
    subcategory.id as subcategory_id
  from tmp_hira_catalogue_products import
  join public.product_categories category
    on category.slug = import.main_category_slug
    and category.is_active = true
  left join public.product_categories subcategory
    on subcategory.slug = import.subcategory_slug
    and subcategory.parent_id = category.id
    and subcategory.is_active = true
)
insert into public.products (
  name,
  slug,
  category_id,
  subcategory_id,
  short_description,
  description,
  product_code,
  material,
  set_contents,
  pieces,
  available_colors,
  features,
  tags,
  image_url,
  gallery_images,
  is_featured,
  is_active,
  sort_order
)
select
  resolved.product_name,
  resolved.slug,
  resolved.category_id,
  resolved.subcategory_id,
  resolved.short_description,
  resolved.description,
  resolved.product_code,
  resolved.material,
  null,
  null,
  resolved.available_colors,
  resolved.features,
  resolved.tags,
  null,
  null,
  resolved.is_featured,
  true,
  resolved.sort_order
from resolved
where not exists (
  select 1
  from public.products existing
  where existing.product_code = resolved.product_code
)
on conflict (slug) do update set
  name = excluded.name,
  category_id = excluded.category_id,
  subcategory_id = excluded.subcategory_id,
  short_description = excluded.short_description,
  description = excluded.description,
  product_code = excluded.product_code,
  material = excluded.material,
  set_contents = excluded.set_contents,
  pieces = excluded.pieces,
  available_colors = excluded.available_colors,
  features = excluded.features,
  tags = excluded.tags,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  updated_at = now();

commit;

